function generarTarjeta() {
  var nombre = document.getElementById("nombre").value;
  var codigo = document.getElementById("codigo").value;
  var pais = document.getElementById("pais").value;

  document.getElementById("nombre-preview").textContent = nombre || "NOMBRE APELLIDO";
  document.getElementById("codigo-preview").textContent = codigo || "000000000";
  document.getElementById("pais-preview").textContent = pais || "PAÍS";

  var fotoInput = document.getElementById("foto");
  if (fotoInput.files && fotoInput.files[0]) {
    var reader = new FileReader();
    reader.onload = function(e) {
      document.getElementById("foto-preview").src = e.target.result;
    }
    reader.readAsDataURL(fotoInput.files[0]);
  }
}

function descargarTarjeta() {
  var formato = prompt("Para descargar tu tarjeta DXN (Escribe PNG o PDF)");
  if (!formato) return;

  var card = document.getElementById("dxn-card");

  html2canvas(card, { 
    useCORS: true, 
    scale: 3,
    logging: false
  }).then(function(canvas) {
    var tmpCanvas = document.createElement("canvas");
    tmpCanvas.width = 1011;
    tmpCanvas.height = 638;
    var ctx = tmpCanvas.getContext("2d");
    
    ctx.imageSmoothingEnabled = true;
    ctx.imageSmoothingQuality = "high";
    ctx.drawImage(canvas, 0, 0, 1011, 638);

    if (formato.toLowerCase() === "png") {
      var enlace = document.createElement("a");
      enlace.download = "tarjeta_dxn.png";
      enlace.href = tmpCanvas.toDataURL("image/png");
      enlace.click();
    } else if (formato.toLowerCase() === "pdf") {
      const { jsPDF } = window.jspdf;
      const pdf = new jsPDF({ orientation: "landscape", unit: "mm", format: [85.6, 54] });
      pdf.addImage(tmpCanvas.toDataURL("image/png"), "PNG", 0, 0, 85.6, 54);
      pdf.save("tarjeta_dxn.pdf");
    } else {
      alert("Formato no válido. Escribe PNG o PDF.");
    }
  });
}
